# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
import threading
from datetime import datetime
from collections import Counter, defaultdict
from flask import Flask, request, jsonify
import numpy as np
from sklearn.linear_model import LogisticRegression
from sklearn.preprocessing import LabelEncoder
import pickle

app = Flask(__name__)

class CrowdsourcedLabelingSystem:
    def __init__(self, data_dir='data'):
        self.data_dir = data_dir
        self.labels_file = os.path.join(data_dir, 'labels.json')
        self.aggregated_file = os.path.join(data_dir, 'aggregated_labels.json')
        self.model_file = os.path.join(data_dir, 'model.pkl')
        self.encoder_file = os.path.join(data_dir, 'encoder.pkl')
        
        os.makedirs(data_dir, exist_ok=True)
        
        self.labels = self._load_labels()
        self.aggregated_labels = self._load_aggregated_labels()
        self.model = None
        self.label_encoder = LabelEncoder()
        self.lock = threading.Lock()
        
    def _load_labels(self):
        if os.path.exists(self.labels_file):
            with open(self.labels_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_labels(self):
        with open(self.labels_file, 'w') as f:
            json.dump(self.labels, f, indent=2)
    
    def _load_aggregated_labels(self):
        if os.path.exists(self.aggregated_file):
            with open(self.aggregated_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_aggregated_labels(self):
        with open(self.aggregated_file, 'w') as f:
            json.dump(self.aggregated_labels, f, indent=2)
    
    def add_label(self, image_id, annotator_id, label, features=None):
        with self.lock:
            if image_id not in self.labels:
                self.labels[image_id] = {
                    'annotations': [],
                    'features': features
                }
            
            annotation = {
                'annotator_id': annotator_id,
                'label': label,
                'timestamp': datetime.now().isoformat()
            }
            
            self.labels[image_id]['annotations'].append(annotation)
            
            if features is not None:
                self.labels[image_id]['features'] = features
            
            self._save_labels()
            
            return True
    
    def aggregate_labels(self, min_annotations=1):
        with self.lock:
            aggregated = {}
            
            for image_id, data in self.labels.items():
                annotations = data['annotations']
                
                if len(annotations) >= min_annotations:
                    label_counts = Counter([ann['label'] for ann in annotations])
                    majority_label = label_counts.most_common(1)[0][0]
                    confidence = label_counts[majority_label] / len(annotations)
                    
                    aggregated[image_id] = {
                        'label': majority_label,
                        'confidence': confidence,
                        'num_annotations': len(annotations),
                        'label_distribution': dict(label_counts),
                        'features': data.get('features')
                    }
            
            self.aggregated_labels = aggregated
            self._save_aggregated_labels()
            
            return aggregated
    
    def get_training_data(self):
        X = []
        y = []
        image_ids = []
        
        for image_id, data in self.aggregated_labels.items():
            if data.get('features') is not None:
                X.append(data['features'])
                y.append(data['label'])
                image_ids.append(image_id)
        
        return np.array(X), np.array(y), image_ids
    
    def train_model(self):
        X, y, image_ids = self.get_training_data()
        
        if len(X) == 0:
            return {'error': 'No training data available'}
        
        self.label_encoder.fit(y)
        y_encoded = self.label_encoder.transform(y)
        
        self.model = LogisticRegression(max_iter=1000, random_state=42)
        self.model.fit(X, y_encoded)
        
        with open(self.model_file, 'wb') as f:
            pickle.dump(self.model, f)
        
        with open(self.encoder_file, 'wb') as f:
            pickle.dump(self.label_encoder, f)
        
        return {
            'status': 'success',
            'num_samples': len(X),
            'num_classes': len(self.label_encoder.classes_),
            'classes': self.label_encoder.classes_.tolist()
        }
    
    def predict(self, features):
        if self.model is None:
            if os.path.exists(self.model_file):
                with open(self.model_file, 'rb') as f:
                    self.model = pickle.load(f)
                with open(self.encoder_file, 'rb') as f:
                    self.label_encoder = pickle.load(f)
            else:
                return {'error': 'Model not trained yet'}
        
        features_array = np.array(features).reshape(1, -1)
        prediction_encoded = self.model.predict(features_array)
        prediction_proba = self.model.predict_proba(features_array)
        
        prediction = self.label_encoder.inverse_transform(prediction_encoded)[0]
        confidence = float(np.max(prediction_proba))
        
        class_probabilities = {
            label: float(prob) 
            for label, prob in zip(self.label_encoder.classes_, prediction_proba[0])
        }
        
        return {
            'prediction': prediction,
            'confidence': confidence,
            'class_probabilities': class_probabilities
        }
    
    def get_statistics(self):
        total_images = len(self.labels)
        total_annotations = sum(len(data['annotations']) for data in self.labels.values())
        aggregated_images = len(self.aggregated_labels)
        
        annotators = set()
        for data in self.labels.values():
            for ann in data['annotations']:
                annotators.add(ann['annotator_id'])
        
        label_distribution = defaultdict(int)
        for data in self.aggregated_labels.values():
            label_distribution[data['label']] += 1
        
        return {
            'total_images': total_images,
            'total_annotations': total_annotations,
            'aggregated_images': aggregated_images,
            'num_annotators': len(annotators),
            'label_distribution': dict(label_distribution),
            'model_trained': self.model is not None or os.path.exists(self.model_file)
        }

labeling_system = CrowdsourcedLabelingSystem()

@app.route('/api/label', methods=['POST'])
def add_label():
    data = request.json
    
    if not data or 'image_id' not in data or 'annotator_id' not in data or 'label' not in data:
        return jsonify({'error': 'Missing required fields: image_id, annotator_id, label'}), 400
    
    image_id = data['image_id']
    annotator_id = data['annotator_id']
    label = data['label']
    features = data.get('features')
    
    success = labeling_system.add_label(image_id, annotator_id, label, features)
    
    if success:
        return jsonify({
            'status': 'success',
            'message': 'Label added successfully',
            'image_id': image_id
        }), 201
    else:
        return jsonify({'error': 'Failed to add label'}), 500

@app.route('/api/aggregate', methods=['POST'])
def aggregate_labels():
    data = request.json or {}
    min_annotations = data.get('min_annotations', 1)
    
    aggregated = labeling_system.aggregate_labels(min_annotations)
    
    return jsonify({
        'status': 'success',
        'num_aggregated': len(aggregated),
        'aggregated_labels': aggregated
    }), 200

@app.route('/api/train', methods=['POST'])
def train_model():
    result = labeling_system.train_model()
    
    if 'error' in result:
        return jsonify(result), 400
    
    return jsonify(result), 200

@app.route('/api/predict', methods=['POST'])
def predict():
    data = request.json
    
    if not data or 'features' not in data:
        return jsonify({'error': 'Missing required field: features'}), 400
    
    features = data['features']
    result = labeling_system.predict(features)
    
    if 'error' in result:
        return jsonify(result), 400
    
    return jsonify(result), 200

@app.route('/api/statistics', methods=['GET'])
def get_statistics():
    stats = labeling_system.get_statistics()
    return jsonify(stats), 200

@app.route('/api/labels/<image_id>', methods=['GET'])
def get_image_labels(image_id):
    if image_id in labeling_system.labels:
        return jsonify(labeling_system.labels[image_id]), 200
    else:
        return jsonify({'error': 'Image not found'}), 404

@app.route('/api/aggregated/<image_id>', methods=['GET'])
def get_aggregated_label(image_id):
    if image_id in labeling_system.aggregated_labels:
        return jsonify(labeling_system.aggregated_labels[image_id]), 200
    else:
        return jsonify({'error': 'Aggregated label not found'}), 404

@app.route('/api/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)